  "type": "QUIZ",
  "lessonText": "Test your knowledge on the basics of sex education.",
  "data": {
    "questions": [
      {
        "question": "What is the primary purpose of sex education?",
        "options": [
          "To promote abstinence",
          "To provide information about sexual health",
          "To encourage early sexual activity",
          "To teach about relationships"
        ],
        "correctAnswer": 1,
        "explanation": "The primary purpose of sex education is to provide accurate information about sexual health."
      },
      {
        "question": "At what age should sex education ideally begin?",
        "options": [
          "5 years old",
          "10 years old",
          "12 years old",
          "It varies by individual"
        ],
        "correctAnswer": 3,
        "explanation": "Sex education should begin at an age appropriate for the individual, considering their maturity and understanding."
      },
      {
        "question": "Which of the following is a key topic in sex education?",
        "options": [
          "Only abstinence",
          "Sexual orientation",
          "How to have sex",
          "None of the above"
        ],
        "correctAnswer": 1,
        "explanation": "Sex education includes discussions on sexual orientation among other important topics."
      },
      {
        "question": "What is consent?",
        "options": [
          "Agreement to engage in sexual activity",
          "Saying yes once",
          "Ignoring someone's refusal",
          "None of the above"
        ],
        "correctAnswer": 0,
        "explanation": "Consent is the clear agreement to engage in sexual activity, and it must be given freely and can be withdrawn at any time."
      }
    ]
  }
}
